{
  "sentences": [
    {
      "text": "今天天氣有點冷，我有點擔心。",
      "pinyin": "Jīntiān tiānqì yǒudiǎn lěng, wǒ yǒudiǎn dānxīn.",
      "pinyin_numeric": "jin1tian1 tian1qi4 you3dian3 leng3, wo3 you3dian3 dan1xin1.",
      "translation_en": "The weather is a bit cold today, I'm a little worried.",
      "translation_ko": "오늘 날씨가 좀 추워서, 제가 조금 걱정돼요."
    },
    {
      "text": "颱風要來了，我心情有點緊張。",
      "pinyin": "Táifēng yào lái le, wǒ xīnqíng yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 yao4 lai2 le0, wo3 xin1qing2 you3dian3 jin3zhang1.",
      "translation_en": "A typhoon is coming, I feel a bit nervous.",
      "translation_ko": "태풍이 오려고 해서, 제 기분이 조금 긴장돼요."
    },
    {
      "text": "晴天讓我有點開心，心情很好。",
      "pinyin": "Qíngtiān ràng wǒ yǒudiǎn kāixīn, xīnqíng hěn hǎo.",
      "pinyin_numeric": "qing2tian1 rang4 wo3 you3dian3 kai1xin1, xin1qing2 hen3 hao3.",
      "translation_en": "The sunny day makes me a little happy, my mood is very good.",
      "translation_ko": "맑은 날씨가 저를 조금 기쁘게 해요, 기분이 아주 좋아요."
    },
    {
      "text": "下雨天路有點滑，走路要小心。",
      "pinyin": "Xiàyǔ tiān lù yǒudiǎn huá, zǒulù yào xiǎoxīn.",
      "pinyin_numeric": "xia4yu3 tian1 lu4 you3dian3 hua2, zou3lu4 yao4 xiao3xin1.",
      "translation_en": "On rainy days the road is a bit slippery, you need to be careful walking.",
      "translation_ko": "비 오는 날 길이 좀 미끄러우니까, 걸을 때 조심해야 해요."
    },
    {
      "text": "今天溫度三十度，天氣有點悶熱。",
      "pinyin": "Jīntiān wēndù sānshí dù, tiānqì yǒudiǎn mēnrè.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, tian1qi4 you3dian3 men1re4.",
      "translation_en": "Today's temperature is 30 degrees, the weather is a bit muggy.",
      "translation_ko": "오늘 기온이 30도인데, 날씨가 좀 후덥지근해요."
    },
    {
      "text": "陰天讓我有點沒精神，不想出門。",
      "pinyin": "Yīntiān ràng wǒ yǒudiǎn méi jīngshén, bù xiǎng chūmén.",
      "pinyin_numeric": "yin1tian1 rang4 wo3 you3dian3 mei2 jing1shen2, bu4 xiang3 chu1men2.",
      "translation_en": "The cloudy day makes me a little listless, I don't want to go out.",
      "translation_ko": "흐린 날씨가 저를 좀 무기력하게 해요, 밖에 나가고 싶지 않아요."
    },
    {
      "text": "颱風天風很大，我有點緊張。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 you3dian3 jin3zhang1.",
      "translation_en": "On typhoon days the wind is very strong, I'm a bit nervous.",
      "translation_ko": "태풍이 오는 날 바람이 많이 불어서, 제가 조금 긴장돼요."
    },
    {
      "text": "今天天氣很舒服，我心情有點放鬆。",
      "pinyin": "Jīntiān tiānqì hěn shūfu, wǒ xīnqíng yǒudiǎn fàngsōng.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 shu1fu0, wo3 xin1qing2 you3dian3 fang4song1.",
      "translation_en": "Today's weather is very comfortable, I feel a bit relaxed.",
      "translation_ko": "오늘 날씨가 아주 쾌적해서, 제 기분이 좀 편안해요."
    },
    {
      "text": "下雨天我有點擔心，因為路很滑。",
      "pinyin": "Xiàyǔ tiān wǒ yǒudiǎn dānxīn, yīnwèi lù hěn huá.",
      "pinyin_numeric": "xia4yu3 tian1 wo3 you3dian3 dan1xin1, yin1wei4 lu4 hen3 hua2.",
      "translation_en": "On rainy days I'm a little worried because the road is very slippery.",
      "translation_ko": "비 오는 날은 제가 조금 걱정돼요, 길이 많이 미끄러우니까요."
    },
    {
      "text": "晴天讓我有精神，心情有點開心。",
      "pinyin": "Qíngtiān ràng wǒ yǒu jīngshén, xīnqíng yǒudiǎn kāixīn.",
      "pinyin_numeric": "qing2tian1 rang4 wo3 you3 jing1shen2, xin1qing2 you3dian3 kai1xin1.",
      "translation_en": "The sunny day gives me energy, my mood is a little happy.",
      "translation_ko": "맑은 날씨가 저에게 활력을 줘요, 기분이 조금 기뻐요."
    }
  ]
}
